SELECT
FROM code_group cg WHERE 1 = 1
AND cg.code_group_id LIKE CONCAT('%', #{codeGroupId}, '%')
AND cg.code_group_name LIKE CONCAT('%', #{codeGroupName}, '%')
AND cg.use_yn = #{useYn}
AND cg.status = #{status}
ORDER BY
cg.code_group_id cg.code_group_name cg.sort_order cg.create_dt cg.code_group_seq
ASC DESC
LIMIT #{safeSize} OFFSET #{offset}

SELECT COUNT(*) FROM code_group cg WHERE 1 = 1
AND cg.code_group_id LIKE CONCAT('%', #{codeGroupId}, '%')
AND cg.code_group_name LIKE CONCAT('%', #{codeGroupName}, '%')
AND cg.use_yn = #{useYn}
AND cg.status = #{status}

SELECT

FROM code_group cg
WHERE cg.code_group_seq = #{codeGroupSeq}

