UPDATE code_group
SET
    code_group_name = #{codeGroupName}
  , description     = #{description}
  , sort_order      = #{sortOrder}
  , use_yn          = #{useYn}
  , modify_dt       = NOW()
  , modify_id       = #{modifyId}
  , modify_ip       = #{modifyIp}
  , status          = #{status}
WHERE code_group_seq = #{codeGroupSeq}
